package com.example.kafkaeventplatform.producer;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

@Service
public class KafkaProducerService {

    private static final Logger logger = LoggerFactory.getLogger(KafkaProducerService.class);

    @Value("${app.kafka.topic.name}")
    private String topicName;

    private final KafkaTemplate<String, String> kafkaTemplate;

    @Autowired
    public KafkaProducerService(KafkaTemplate<String, String> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void sendMessage(String message) {
        logger.info(String.format("Producing message to topic %s: %s", topicName, message));
        kafkaTemplate.send(topicName, message);
    }

    public void sendMessage(String key, String message) {
        logger.info(String.format("Producing message with key '%s' to topic %s: %s", key, topicName, message));
        kafkaTemplate.send(topicName, key, message);
    }
}

