package com.example.kafkaeventplatform.controller;

import com.example.kafkaeventplatform.producer.KafkaProducerService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/events")
public class EventController {

    private final KafkaProducerService producerService;

    @Autowired
    public EventController(KafkaProducerService producerService) {
        this.producerService = producerService;
    }

    @PostMapping("/publish/{message}")
    public ResponseEntity<String> publishEvent(@PathVariable String message) {
        producerService.sendMessage(message);
        return ResponseEntity.ok("Event published: " + message);
    }

    @PostMapping("/publish/{key}/{message}")
    public ResponseEntity<String> publishEventWithKey(@PathVariable String key, @PathVariable String message) {
        producerService.sendMessage(key, message);
        return ResponseEntity.ok("Event published with key '" + key + "': " + message);
    }
}